code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Badge, Button, icon } from 'decantr/components';

code.example:
function ContentCardGrid({ items }) {
  const { div, h3, p, span, a } = tags;

  return div({ class: css('_grid _gc1 _md:gc2 _lg:gc3 _gap4') },
    ...items.map(item =>
      Card({ class: css('_flex _col _gap0') },
        div({ class: css('_flex _aic _gap2 _p4 _pb0') },
          Badge({ variant: 'outline', size: 'sm' }, item.type),
          Badge({ variant: item.namespace === '@official' ? 'primary' : 'secondary', size: 'sm' }, item.namespace)
        ),
        div({ class: css('_p4 _flex _col _gap2 _flex1') },
          a({ href: `/registry/${item.type}/${item.namespace}/${item.slug}`, class: css('_heading4 _fgfg _hover:fgprimary _no-underline') }, item.name),
          p({ class: css('_bodysm _fgmuted _line-clamp2') }, item.description)
        ),
        div({ class: css('_flex _aic _jcsb _p4 _pt0 _bordert _bordermuted/20') },
          span({ class: css('_textxs _fgmuted') }, `v${item.version}`),
          Button({ variant: 'ghost', size: 'xs' }, icon('arrow-right', { size: '0.875rem' }))
        )
      )
    )
  );
}

