code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Badge, Button, icon } from 'decantr/components';

code.example:
function ContentCardGridEditable({ items, onEdit, onDelete }) {
  const { div, h3, p, span } = tags;
  const statusVariant = { published: 'success', pending: 'warning', rejected: 'destructive' };

  return div({ class: css('_grid _gc1 _md:gc2 _lg:gc3 _gap4') },
    ...items.map(item =>
      Card({ class: css('_flex _col') },
        div({ class: css('_flex _aic _jcsb _p4 _pb0') },
          div({ class: css('_flex _aic _gap2') },
            Badge({ variant: 'outline', size: 'sm' }, item.type),
            Badge({ variant: statusVariant[item.status] || 'secondary', size: 'sm' }, item.status)
          )
        ),
        div({ class: css('_p4 _flex _col _gap2 _flex1') },
          h3({ class: css('_heading4') }, item.name),
          p({ class: css('_bodysm _fgmuted _line-clamp2') }, item.description)
        ),
        div({ class: css('_flex _aic _jcsb _p4 _pt0 _bordert _bordermuted/20') },
          span({ class: css('_textxs _fgmuted') }, item.published_at ? `Published ${item.published_at}` : 'Draft'),
          div({ class: css('_flex _gap2') },
            Button({ variant: 'ghost', size: 'sm', onclick: () => onEdit(item.id) }, icon('edit', { size: '0.875rem' }), ' Edit'),
            Button({ variant: 'ghost', size: 'sm', onclick: () => onDelete(item.id) }, icon('trash', { size: '0.875rem' }))
          )
        )
      )
    )
  );
}

